<?php namespace Blue\Controllers; use Blue\Core\Database; use Blue\Services\Audit;
class ApiController { public function webhook(){ header('Content-Type: application/json'); $payload=json_decode(file_get_contents('php://input'),true) ?: $_POST; $event=$payload['event']??'incoming.webhook'; $id=Database::insert('INSERT INTO integration_events(event_name,source_app,payload,status,created_at) VALUES(?,?,?,?,NOW())',[$event,$payload['source_app']??'external',json_encode($payload),'received']); Audit::log('webhook.received','integration_event',$id,$payload); echo json_encode(['success'=>true,'event_id'=>$id]); } }
